-- ERPNexus Support App - brand new database schema for a new Supabase project
create extension if not exists pgcrypto;
create table public.companies (id uuid primary key default gen_random_uuid(), name text not null unique, is_main_account boolean not null default false, is_active boolean not null default true, billing_name text, billing_contact_name text, billing_address_line_1 text, billing_address_line_2 text, billing_city text, billing_state text, billing_zip text, billing_email text, created_at timestamptz not null default now());
create table public.profiles (id uuid primary key, email text unique, full_name text, role text not null default 'user' check (role in ('admin','support','client_admin','user')), company_id uuid references public.companies(id) on delete set null, is_active boolean not null default true, created_at timestamptz not null default now());
create table public.invoices (id uuid primary key default gen_random_uuid(), invoice_number text not null unique, company_id uuid references public.companies(id) on delete set null, main_account_company_id uuid references public.companies(id) on delete set null, status text not null default 'Draft' check (status in ('Draft','Sent','Paid','Void')), due_date date, payment_terms_label text default 'Net 30', remit_to_name text, remit_to_company_name text, remit_to_address_line_1 text, remit_to_address_line_2 text, remit_to_city text, remit_to_state text, remit_to_zip text, notes text, subtotal numeric(12,2) not null default 0, tax_amount numeric(12,2) not null default 0, total_amount numeric(12,2) not null default 0, approved_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.tickets (id uuid primary key default gen_random_uuid(), ticket_number text not null unique, user_id uuid not null references public.profiles(id) on delete cascade, company_id uuid references public.companies(id) on delete set null, assigned_company_id uuid references public.companies(id) on delete set null, assigned_to_user_id uuid references public.profiles(id) on delete set null, title text not null, description text not null, priority text not null default 'Medium' check (priority in ('Low','Medium','High','Urgent')), status text not null default 'New' check (status in ('New','In Progress','Waiting on User','Resolved','Pending Invoicing Approval','Pending Invoicing','Invoiced')), invoice_approval_status text not null default 'Not Needed' check (invoice_approval_status in ('Not Needed','Pending Approval','Pending Invoicing','Invoiced')), resolution_note text, work_completed_on date, invoice_id uuid references public.invoices(id) on delete set null, approved_by uuid references public.profiles(id) on delete set null, approved_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.work_logs (id uuid primary key default gen_random_uuid(), ticket_id uuid not null references public.tickets(id) on delete cascade, user_id uuid not null references public.profiles(id) on delete cascade, work_date date not null, work_completed_on date, notes text not null, invoice_line_description text, hours_worked numeric(8,2) not null default 0, billable boolean not null default true, approval_status text not null default 'Pending Approval' check (approval_status in ('Pending Approval','Approved','Rejected')), invoice_id uuid references public.invoices(id) on delete set null, created_at timestamptz not null default now());
create table public.invoice_items (id uuid primary key default gen_random_uuid(), invoice_id uuid not null references public.invoices(id) on delete cascade, work_log_id uuid references public.work_logs(id) on delete set null, work_completed_on date, description text not null, hours numeric(8,2) not null default 0, rate numeric(10,2) not null default 0, amount numeric(12,2) not null default 0, created_at timestamptz not null default now());
create table public.invoice_settings (id uuid primary key default gen_random_uuid(), company_id uuid not null unique references public.companies(id) on delete cascade, pay_to_name text, pay_to_company_name text, pay_to_address_line_1 text, pay_to_address_line_2 text, pay_to_city text, pay_to_state text, pay_to_zip text, default_payment_terms_days integer not null default 30, default_payment_terms_label text not null default 'Net 30', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), updated_by uuid references public.profiles(id) on delete set null);
create index idx_profiles_company_id on public.profiles(company_id);
create index idx_tickets_company_id on public.tickets(company_id);
create index idx_tickets_status on public.tickets(status);
create index idx_tickets_invoice_status on public.tickets(invoice_approval_status);
create index idx_work_logs_invoice_id on public.work_logs(invoice_id);
create index idx_invoices_company_id on public.invoices(company_id);
create or replace function public.handle_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end; $$;
create or replace function public.enforce_main_account_role_rules() returns trigger language plpgsql as $$ declare target_company_is_main boolean; main_company_id uuid; begin if new.company_id is null and new.role in ('support', 'admin') then select id into main_company_id from public.companies where is_main_account = true limit 1; new.company_id := main_company_id; end if; if new.company_id is not null then select is_main_account into target_company_is_main from public.companies where id = new.company_id; end if; if new.role in ('support', 'admin') and coalesce(target_company_is_main, false) = false then raise exception 'Support and Admin roles must belong to the Main Account company.'; end if; if new.role = 'admin' then select id into main_company_id from public.companies where is_main_account = true limit 1; new.company_id := main_company_id; end if; return new; end; $$;
create or replace function public.enforce_invoice_settings_main_account() returns trigger language plpgsql as $$ declare target_company_is_main boolean; begin select is_main_account into target_company_is_main from public.companies where id = new.company_id; if coalesce(target_company_is_main, false) = false then raise exception 'Invoice settings can only be attached to the Main Account company.'; end if; return new; end; $$;
create trigger trg_profiles_main_account_role_rules before insert or update on public.profiles for each row execute function public.enforce_main_account_role_rules();
create trigger trg_invoice_settings_updated_at before update on public.invoice_settings for each row execute function public.handle_updated_at();
create trigger trg_invoice_settings_main_account_only before insert or update on public.invoice_settings for each row execute function public.enforce_invoice_settings_main_account();
create trigger trg_tickets_updated_at before update on public.tickets for each row execute function public.handle_updated_at();
create trigger trg_invoices_updated_at before update on public.invoices for each row execute function public.handle_updated_at();
alter table public.companies enable row level security;
alter table public.profiles enable row level security;
alter table public.tickets enable row level security;
alter table public.work_logs enable row level security;
alter table public.invoices enable row level security;
alter table public.invoice_items enable row level security;
alter table public.invoice_settings enable row level security;
create or replace function public.is_main_admin_user() returns boolean language sql stable as $$ select exists (select 1 from public.profiles p join public.companies c on c.id = p.company_id where p.id = auth.uid() and p.role = 'admin' and c.is_main_account = true); $$;
create or replace function public.is_main_support_user() returns boolean language sql stable as $$ select exists (select 1 from public.profiles p join public.companies c on c.id = p.company_id where p.id = auth.uid() and p.role in ('admin','support') and c.is_main_account = true); $$;
create policy "companies_read" on public.companies for select to authenticated using (true);
create policy "companies_admin_manage" on public.companies for all to authenticated using (public.is_main_admin_user()) with check (public.is_main_admin_user());
create policy "profiles_self_read" on public.profiles for select to authenticated using (id = auth.uid() or public.is_main_support_user());
create policy "profiles_admin_manage" on public.profiles for all to authenticated using (public.is_main_admin_user()) with check (public.is_main_admin_user());
create policy "tickets_read" on public.tickets for select to authenticated using (user_id = auth.uid() or public.is_main_support_user() or company_id in (select company_id from public.profiles where id = auth.uid()));
create policy "tickets_insert" on public.tickets for insert to authenticated with check (user_id = auth.uid() or public.is_main_support_user());
create policy "tickets_update" on public.tickets for update to authenticated using (user_id = auth.uid() or public.is_main_support_user()) with check (user_id = auth.uid() or public.is_main_support_user());
create policy "work_logs_read" on public.work_logs for select to authenticated using (public.is_main_support_user() or user_id = auth.uid());
create policy "work_logs_write" on public.work_logs for insert to authenticated with check (public.is_main_support_user() or user_id = auth.uid());
create policy "work_logs_update" on public.work_logs for update to authenticated using (public.is_main_support_user() or user_id = auth.uid()) with check (public.is_main_support_user() or user_id = auth.uid());
create policy "invoices_read" on public.invoices for select to authenticated using (public.is_main_support_user() or company_id in (select company_id from public.profiles where id = auth.uid()));
create policy "invoices_manage" on public.invoices for all to authenticated using (public.is_main_support_user()) with check (public.is_main_support_user());
create policy "invoice_items_read" on public.invoice_items for select to authenticated using (true);
create policy "invoice_items_manage" on public.invoice_items for all to authenticated using (public.is_main_support_user()) with check (public.is_main_support_user());
create policy "invoice_settings_read" on public.invoice_settings for select to authenticated using (public.is_main_support_user());
create policy "invoice_settings_manage" on public.invoice_settings for all to authenticated using (public.is_main_admin_user()) with check (public.is_main_admin_user());
insert into public.companies (name, is_main_account, billing_name) values ('ERPNexus', true, 'ERPNexus') on conflict (name) do nothing;
